 */
template <>
void matrix<double>::eigensystem(vector<double> &d, matrix<double> &U) const {
  assert(r == c);
  assert(U.r == r and U.c == c);
  assert(d.size() == r);

  char JOBZ, UPLO;
  integer INFO = 0, N, LDA, LWORK;

  JOBZ = 'V'; // calculates eigenvectors too
  UPLO = 'L'; // lower triangle is stored
  N = (integer)r;
  erase(U.v);
  U.v = this->v;
  LDA = r;
  LWORK = 3 * N; // N*(N+2);
  vector<doublereal> WORK(LWORK);

  dsyev_(&JOBZ, &UPLO, &N, (doublereal *)&U.v[0], &LDA, (doublereal *)&d[0],
         WORK.data(), &LWORK, &INFO);

  if (!((int)INFO == 0)) {
    cout << "dimension : " << r << " x " << c << endl;
    cout << *this << endl; // TEMPO
    throw std::runtime_error(
        std::string("bad INFO value from dsyev (eigensystem)") +
        std::to_string((int)INFO));
  }
}

