}

/**
 inverts the current matrix (replaces its content)
 */
template <> void matrix<Complex>::inverse() {
  assert(r == c);
  if (r == 0)
    return;
  integer INFO = 0, M, N, LDA;

  vector<integer> IPIV(r);
  vector<doublecomplex> WORK(r);

  N = r;
  M = r;
  LDA = r;

  zgetrf_(&M, &N, (doublecomplex *)&v[0], &LDA, IPIV.data(), &INFO);
  assert((int)INFO == 0);
  zgetri_(&N, (doublecomplex *)&v[0], &LDA, IPIV.data(), WORK.data(), &N,
          &INFO);
  assert((int)INFO == 0);
}

/**
 Absolute value (module) of the determinant of a complex matrix
 Destroys the matrix !
 */
template <> Complex matrix<Complex>::determinant() {
  Complex z;
  size_t i;
  if (r == 0)
    return Complex(0);

  integer INFO = 0, LDA;

  vector<integer> IPIV(r);
  LDA = r;
  zgetrf_((integer *)&r, (integer *)&c, (doublecomplex *)&v[0], &LDA,
          IPIV.data(), &INFO);
  assert((int)INFO == 0);
  z = Complex(1.0);
  for (i = 0; i < r; ++i)
    z *= v[i + i * r];
  return (z);
}

