/**
 returns true if the matrix is orthogonal
 */
template <> bool matrix<double>::is_orthogonal(double accuracy) {
  if (r != c)
    return false;
  for (size_t i = 0; i < r; ++i) {
    for (size_t j = 0; j <= i; ++j) {
      double z = 0.0;
      for (size_t k = 0; k < r; ++k) {
        z += v[k + i * r] * v[k + j * r];
      }
      if (i == j and abs(z - 1.0) > accuracy)
        return false;
      if (i != j and abs(z) > accuracy)
        return false;
    }
  }
  return true;
}

/**
 puts in the current matrix the matrix $L$ of the Cholesky decomposition of A =
 L.transpose(L)
 */
template <> bool matrix<double>::cholesky(matrix<double> &A) {
  char UPLO;
  integer INFO = 0, N, LDA;

  UPLO = 'L'; // lower triangle is stored
  N = (integer)r;
  LDA = A.r;
  set_size(A.r);
  for (size_t i = 0; i < r; i++) {
    for (size_t j = 0; j <= i; j++)
      v[i + r * j] = A(i, j);
  }

  dpotrf_(&UPLO, &N, (doublereal *)&v[0], &LDA, &INFO);

  if ((int)INFO == 0)
    return true;
  else
    return false;
}

/**
 puts in the current matrix the matrix $L$ of the Cholesky decomposition of A =
 L.transpose(L)
 */
template <> bool matrix<double>::triangular_inverse() {
  char UPLO, DIAG;
  integer INFO = 0, N, LDA;

  UPLO = 'L'; // lower triangle is stored
  DIAG = 'N'; // not a unit diagonal
  N = (integer)r;
  LDA = (integer)r;
  dtrtri_(&UPLO, &DIAG, &N, (doublereal *)&v[0], &LDA, &INFO);
  if ((int)INFO == 0)
    return true;
  else
    return false;
}

